mapper.update:
UPDATE TB_BBS_SURVEY
SET VIEW_CNT = VIEW_CNT + 1
WHERE SRVY_SN = #{srvySn}

mapper.select:
SELECT s.SRVY_SN AS srvySn, s.SRVY_TTL AS srvyTtl, s.SRVY_QITEM AS srvyQitem, s.SRVY_BGNG_DT AS srvyBgngDt, s.SRVY_END_DT AS srvyEndDt, s.SRVY_SCOPE AS srvyScope, s.BBS_TYPE AS bbsType, s.CO_SN AS coSn, s.COHORT_SN AS cohortSn, s.USER_SN AS userSn, u.USER_NM AS userNm, s.FORM_UUID AS formUuid, s.VIEW_CNT AS viewCnt, s.SRVY_FRST_WRT_DT AS srvyFrstWrtDt, s.SRVY_LAST_MDFCN_DT AS srvyLastMdfcnDt, s.DEL_YN AS delYn FROM TB_BBS_SURVEY s JOIN TB_USER u ON s.USER_SN = u.USER_SN WHERE s.DEL_YN = FALSE
AND s.BBS_TYPE = #{bbsType}
AND s.CO_SN = #{coSn}
AND (s.COHORT_SN = #{cohortSn} OR s.COHORT_SN IS NULL)
AND s.SRVY_SCOPE IN
#{scope}
ORDER BY s.SRVY_SN DESC

mapper.update:
UPDATE TB_BBS_SURVEY
SET DEL_YN = TRUE,
SRVY_LAST_MDFCN_DT = NOW()
WHERE SRVY_SN = #{srvySn}
AND USER_SN = #{userSn}
